INSERT INTO public.daily_scenario_phrases (scenario_id, order_index, phrase, translation, romanization)
VALUES
('e1d6a9d6-ea8d-5cf6-bfba-f8dc496f34db', 1, 'Можно мне кофе, пожалуйста?', 'Can I have a coffee, please?', 'Mozhno mne kofe, pozhaluysta?'),
('e1d6a9d6-ea8d-5cf6-bfba-f8dc496f34db', 2, 'Как прошёл твой день?', 'How was your day?', 'Kak proshyol tvoy den?'),
('e1d6a9d6-ea8d-5cf6-bfba-f8dc496f34db', 3, 'Это очень вкусно!', 'This is very tasty!', 'Eto ochen vkusno!'),
('e1d6a9d6-ea8d-5cf6-bfba-f8dc496f34db', 4, 'Давай встретимся здесь завтра.', 'Let''s meet here tomorrow.', 'Davay vstretimsya zdes'' zavtra.'),
('e1d6a9d6-ea8d-5cf6-bfba-f8dc496f34db', 5, 'Счёт, пожалуйста.', 'The bill, please.', 'Schyot, pozhaluysta.'),
('311b5e7a-fbcf-5e56-aa17-7d5e064c23b1', 1, '我要一杯咖啡，唔該。', 'I’d like a cup of coffee, please.', 'ngo5 jiu3 jat1 bui1 gaa3 fe1, m4 goi1.'),
('311b5e7a-fbcf-5e56-aa17-7d5e064c23b1', 2, '味道好好。', 'It tastes really good.', 'mei6 dou6 hou2 hou2.'),
('311b5e7a-fbcf-5e56-aa17-7d5e064c23b1', 3, '你今日點呀？', 'How are you today?', 'nei5 gam1 jat6 dim2 aa3?'),
('311b5e7a-fbcf-5e56-aa17-7d5e064c23b1', 4, '可以埋單嗎？', 'Can we have the bill?', 'ho2 ji5 maai4 daan1 maa3?'),
('311b5e7a-fbcf-5e56-aa17-7d5e064c23b1', 5, '我想再嚟一次。', 'I want to come again.', 'ngo5 soeng2 zoi3 lai4 jat1 ci3.'),
('f42d7fae-1aa9-5fae-b3f2-b48c72524a4f', 1, 'Когда тебе удобно?', 'When is it convenient for you?', 'Kogda tebe udobno?'),
('f42d7fae-1aa9-5fae-b3f2-b48c72524a4f', 2, 'Где мы встретимся?', 'Where shall we meet?', 'Gde my vstretimsya?'),
('f42d7fae-1aa9-5fae-b3f2-b48c72524a4f', 3, 'Я свободен вечером.', 'I’m free in the evening.', 'Ya svoboden vecherom.'),
('f42d7fae-1aa9-5fae-b3f2-b48c72524a4f', 4, 'Позвони мне завтра.', 'Call me tomorrow.', 'Pozvoni mne zavtra.'),
('f42d7fae-1aa9-5fae-b3f2-b48c72524a4f', 5, 'Отличная идея!', 'Great idea!', 'Otlichnaya ideya!'),
('0f0afd95-d3be-528e-b642-be73d65f03e5', 1, '你星期六得閒嗎？', 'Are you free on Saturday?', 'nei5 sing1 kei4 luk6 dak1 haan4 maa3?'),
('0f0afd95-d3be-528e-b642-be73d65f03e5', 2, '我哋一齊去啦！', 'Let’s go together!', 'ngo5 dei6 jat1 cai4 heoi3 laa1!'),
('0f0afd95-d3be-528e-b642-be73d65f03e5', 3, '去邊度好呢？', 'Where should we go?', 'heoi3 bin1 dou6 hou2 ne1?'),
('0f0afd95-d3be-528e-b642-be73d65f03e5', 4, '好主意！', 'Good idea!', 'hou2 zyu2 ji3!'),
('0f0afd95-d3be-528e-b642-be73d65f03e5', 5, '到時再聯絡。', 'Let’s get in touch then.', 'dou3 si4 zoi3 lyun4 lok3.'),
('566443c6-c280-5542-996f-27e641725881', 1, 'Где платформа номер пять?', 'Where is platform number five?', 'Gde platforma nomer pyat''?'),
('566443c6-c280-5542-996f-27e641725881', 2, 'Поезд задерживается.', 'The train is delayed.', 'Poezd zaderzhivaetsya.'),
('566443c6-c280-5542-996f-27e641725881', 3, 'Сколько стоит билет?', 'How much is the ticket?', 'Skol''ko stoit bilet?'),
('566443c6-c280-5542-996f-27e641725881', 4, 'Когда отправление?', 'When is the departure?', 'Kogda otpravlenie?'),
('566443c6-c280-5542-996f-27e641725881', 5, 'Хорошо, поехали!', 'let’s go!', 'Khorosho, poekhali!,Alright'),
('7ebcc524-3d03-553b-bb8f-99bd0e1e43d8', 1, '月台喺邊度？', 'Where is the platform?', 'jyut6 toi4 hai2 bin1 dou6?'),
('7ebcc524-3d03-553b-bb8f-99bd0e1e43d8', 2, '火車遲咗。', 'The train is late.', 'fo2 ce1 ci4 zo2.'),
('7ebcc524-3d03-553b-bb8f-99bd0e1e43d8', 3, '幾多錢一張票？', 'How much is a ticket?', 'gei2 do1 cin2 jat1 zoeng1 piu3?'),
('7ebcc524-3d03-553b-bb8f-99bd0e1e43d8', 4, '幾點開出？', 'What time does it depart?', 'gei2 dim2 hoi1 ceot1?'),
('7ebcc524-3d03-553b-bb8f-99bd0e1e43d8', 5, '好啦，一齊走喇！', 'let’s go!', 'hou2 laa1, jat1 cai4 zau2 laa3!,Alright'),
('d6acd05b-ca37-5856-ae7a-7df3ea6db34a', 1, 'Можно примерить?', 'Can I try it on?', 'Mozhno primyerit''?'),
('d6acd05b-ca37-5856-ae7a-7df3ea6db34a', 2, 'У вас есть скидка?', 'Do you have a discount?', 'U vas yest'' skidka?'),
('d6acd05b-ca37-5856-ae7a-7df3ea6db34a', 3, 'Сколько это стоит?', 'How much does this cost?', 'Skol''ko eto stoit?'),
('d6acd05b-ca37-5856-ae7a-7df3ea6db34a', 4, 'Мне нравится этот цвет.', 'I like this color.', 'Mne nravitsya etot tsvet.'),
('d6acd05b-ca37-5856-ae7a-7df3ea6db34a', 5, 'Возьму это.', 'I’ll take it.', 'Voz''mu eto.'),
('8ff51436-e8c7-516e-b77d-1388a65d4350', 1, '可唔可以試下？', 'Can I try it on?', 'ho2 m4 ho2 ji5 si3 haa5?'),
('8ff51436-e8c7-516e-b77d-1388a65d4350', 2, '幾多錢呀？', 'How much is it?', 'gei2 do1 cin2 aa3?'),
('8ff51436-e8c7-516e-b77d-1388a65d4350', 3, '有冇折扣？', 'Is there a discount?', 'jau5 mou5 zit3 kau3?'),
('8ff51436-e8c7-516e-b77d-1388a65d4350', 4, '我鍾意呢個顏色。', 'I like this color.', 'ngo5 zung1 ji3 ni1 go3 ngaan4 sik1.'),
('8ff51436-e8c7-516e-b77d-1388a65d4350', 5, '我要買呢個。', 'I’ll buy this one.', 'ngo5 jiu3 maai5 ni1 go3.'),
('1a559940-2d6a-5c25-a367-d27fa90ea7c2', 1, 'Что вы посоветуете?', 'What do you recommend?', 'Chto vy posovetuyete?'),
('1a559940-2d6a-5c25-a367-d27fa90ea7c2', 2, 'Я буду суп и рыбу.', 'I’ll have soup and fish.', 'Ya budu sup i rybu.'),
('1a559940-2d6a-5c25-a367-d27fa90ea7c2', 3, 'Это выглядит вкусно!', 'That looks delicious!', 'Eto vyglyadit vkusno!'),
('1a559940-2d6a-5c25-a367-d27fa90ea7c2', 4, 'Принесите счёт, пожалуйста.', 'Could we have the bill, please?', 'Prinesite schyot, pozhaluysta.'),
('1a559940-2d6a-5c25-a367-d27fa90ea7c2', 5, 'Спасибо за ужин!', 'Thanks for dinner!', 'Spasibo za uzhin!'),
('42877b04-0b81-5ccc-a64b-790b6f13f0a6', 1, '有乜嘢推介？', 'What do you recommend?', 'jau5 mat1 je5 teoi1 gaai3?'),
('42877b04-0b81-5ccc-a64b-790b6f13f0a6', 2, '我要個湯同魚。', 'I’ll have soup and fish.', 'ngo5 jiu3 go3 tong1 tung4 jyu4.'),
('42877b04-0b81-5ccc-a64b-790b6f13f0a6', 3, '好味呀！', 'It’s delicious!', 'hou2 mei6 aa3!'),
('42877b04-0b81-5ccc-a64b-790b6f13f0a6', 4, '埋單唔該。', 'The bill, please.', 'maai4 daan1 m4 goi1.'),
('42877b04-0b81-5ccc-a64b-790b6f13f0a6', 5, '多謝請我食飯。', 'Thanks for dinner!', 'do1 ze6 cing2 ngo5 sik6 faan6.'),
('38138598-5b8b-5cb3-8e06-8bafb10f85ce', 1, 'Тебе понравился фильм?', 'Did you like the movie?', 'Tebe ponravilsya fil''m?'),
('38138598-5b8b-5cb3-8e06-8bafb10f85ce', 2, 'Сюжет был интересный.', 'The plot was interesting.', 'Suzhet byl interesnyy.'),
('38138598-5b8b-5cb3-8e06-8bafb10f85ce', 3, 'Мне понравился актёр.', 'I liked the actor.', 'Mne ponravilsya aktyor.'),
('38138598-5b8b-5cb3-8e06-8bafb10f85ce', 4, 'Конец был неожиданным.', 'The ending was unexpected.', 'Konyets byl neozhidannym.'),
('38138598-5b8b-5cb3-8e06-8bafb10f85ce', 5, 'Пойдём в кино снова!', 'Let’s go to the cinema again!', 'Poydyom v kino snova!'),
('07639b0d-6cb5-5761-8f17-a756757dbaa3', 1, '你覺得套戲點呀？', 'How was the movie?', 'nei5 gok3 dak1 tou3 hei3 dim2 aa3?'),
('07639b0d-6cb5-5761-8f17-a756757dbaa3', 2, '個故事幾有趣。', 'The story was interesting.', 'go3 gu3 si6 gei2 jau5 ceoi3.'),
('07639b0d-6cb5-5761-8f17-a756757dbaa3', 3, '我鍾意個演員。', 'I liked the actor.', 'ngo5 zung1 ji3 go3 jin2 jyun4.'),
('07639b0d-6cb5-5761-8f17-a756757dbaa3', 4, '結局好出奇。', 'The ending was surprising.', 'git3 guk6 hou2 ceot1 kei4.'),
('07639b0d-6cb5-5761-8f17-a756757dbaa3', 5, '下次再睇啦！', 'Let’s watch another one next time!', 'haa6 ci3 zoi3 tai2 laa1!'),
('2e81f884-2754-5e32-9f0f-ff7c4c77cf05', 1, 'Куда поедем?', 'Where shall we go?', 'Kuda poyedem?'),
('2e81f884-2754-5e32-9f0f-ff7c4c77cf05', 2, 'Погода будет хорошая.', 'The weather will be nice.', 'Pogoda budet khoroshaya.'),
('2e81f884-2754-5e32-9f0f-ff7c4c77cf05', 3, 'Возьму камеру.', 'I’ll take the camera.', 'Voz''mu kameru.'),
('2e81f884-2754-5e32-9f0f-ff7c4c77cf05', 4, 'Хочу отдохнуть на пляже.', 'I want to relax on the beach.', 'Khochu otdokhnut'' na plyazhe.'),
('2e81f884-2754-5e32-9f0f-ff7c4c77cf05', 5, 'Отличный план!', 'Great plan!', 'Otlichnyy plan!'),
('f8a9dd27-fdcb-5ba1-b9c0-aac7e4f1f706', 1, '去邊度好？', 'Where should we go?', 'heoi3 bin1 dou6 hou2?'),
('f8a9dd27-fdcb-5ba1-b9c0-aac7e4f1f706', 2, '聽日天氣好。', 'The weather will be good tomorrow.', 'ting1 jat6 tin1 hei3 hou2.'),
('f8a9dd27-fdcb-5ba1-b9c0-aac7e4f1f706', 3, '我帶相機。', 'I’ll bring my camera.', 'ngo5 daai3 soeng2 gei1.'),
('f8a9dd27-fdcb-5ba1-b9c0-aac7e4f1f706', 4, '我想去沙灘休息。', 'I want to relax on the beach.', 'ngo5 soeng2 heoi3 sa1 taan1 jau1 sik1.'),
('f8a9dd27-fdcb-5ba1-b9c0-aac7e4f1f706', 5, '好計劃呀！', 'Great plan!', 'hou2 gai3 waak6 aa3!'),
('3ec22f4f-ce84-5bc8-a50d-be42116d8953', 1, 'У меня болит голова.', 'I have a headache.', 'U menya bolit golova.'),
('3ec22f4f-ce84-5bc8-a50d-be42116d8953', 2, 'Мне нужно лекарство.', 'I need some medicine.', 'Mne nuzhno lekarstvo.'),
('3ec22f4f-ce84-5bc8-a50d-be42116d8953', 3, 'Как долго мне отдыхать?', 'How long should I rest?', 'Kak dolgo mne otdykhat''?'),
('3ec22f4f-ce84-5bc8-a50d-be42116d8953', 4, 'Температура высокая.', 'My temperature is high.', 'Temperatura vysokaya.'),
('3ec22f4f-ce84-5bc8-a50d-be42116d8953', 5, 'Спасибо, доктор.', 'Thank you, doctor.', 'Spasibo, doktor.'),
('e6944a86-66e8-5011-82af-a1aaba322599', 1, '我頭痛。', 'I have a headache.', 'ngo5 tau4 tung3.'),
('e6944a86-66e8-5011-82af-a1aaba322599', 2, '請畀啲藥我。', 'Please give me some medicine.', 'cing2 bei2 di1 joek6 ngo5.'),
('e6944a86-66e8-5011-82af-a1aaba322599', 3, '要休息幾耐？', 'How long should I rest?', 'jiu3 jau1 sik1 gei2 noi6?'),
('e6944a86-66e8-5011-82af-a1aaba322599', 4, '我發燒。', 'I have a fever.', 'ngo5 faat3 siu1.'),
('e6944a86-66e8-5011-82af-a1aaba322599', 5, '多謝醫生。', 'Thank you, doctor.', 'do1 ze6 ji1 sang1.'),
('d9df098d-0321-5238-a7b3-1143faca8ca4', 1, 'Когда встреча?', 'When is the meeting?', 'Kogda vstrecha?'),
('d9df098d-0321-5238-a7b3-1143faca8ca4', 2, 'Проект почти готов.', 'The project is almost ready.', 'Proyekt pochti gotov.'),
('d9df098d-0321-5238-a7b3-1143faca8ca4', 3, 'Хорошая идея!', 'Good idea!', 'Khoroshaya ideya!'),
('d9df098d-0321-5238-a7b3-1143faca8ca4', 4, 'Мне нужно закончить отчёт.', 'I need to finish the report.', 'Mne nuzhno zakonchit'' otchot.'),
('d9df098d-0321-5238-a7b3-1143faca8ca4', 5, 'Удачи на встрече!', 'Good luck at the meeting!', 'Udachi na vstreche!'),
('1a9a7c86-1cc7-5bdb-a526-1fcc91654267', 1, '會議幾點？', 'What time is the meeting?', 'wui6 ji5 gei2 dim2?'),
('1a9a7c86-1cc7-5bdb-a526-1fcc91654267', 2, '個計劃差唔多好。', 'The project is almost ready.', 'go3 gai3 waak6 caa1 m4 do1 hou2.'),
('1a9a7c86-1cc7-5bdb-a526-1fcc91654267', 3, '好主意！', 'Good idea!', 'hou2 zyu2 ji3!'),
('1a9a7c86-1cc7-5bdb-a526-1fcc91654267', 4, '我要完成報告。', 'I need to finish the report.', 'ngo5 jiu3 jyun4 sing4 bou3 gou3.'),
('1a9a7c86-1cc7-5bdb-a526-1fcc91654267', 5, '祝你會議順利！', 'Good luck with the meeting!', 'zuk1 nei5 wui6 ji5 seon6 lei6!'),
('6536d374-eb9f-5bbb-85e9-64306c07447d', 1, 'Идите прямо.', 'Go straight.', 'Idite pryamo.'),
('6536d374-eb9f-5bbb-85e9-64306c07447d', 2, 'Поверните направо.', 'Turn right.', 'Povernite napravo.'),
('6536d374-eb9f-5bbb-85e9-64306c07447d', 3, 'Кафе рядом.', 'The café is nearby.', 'Kafe ryadom.'),
('6536d374-eb9f-5bbb-85e9-64306c07447d', 4, 'Это далеко отсюда?', 'Is it far from here?', 'Eto daleko otsyuda?'),
('6536d374-eb9f-5bbb-85e9-64306c07447d', 5, 'Спасибо за помощь!', 'Thanks for your help!', 'Spasibo za pomoshch!'),
('7bac4990-83cd-5d5a-a7b9-20993706544a', 1, '直行。', 'Go straight.', 'zik6 haang4.'),
('7bac4990-83cd-5d5a-a7b9-20993706544a', 2, '右轉。', 'Turn right.', 'jau6 zyun2.'),
('7bac4990-83cd-5d5a-a7b9-20993706544a', 3, '咖啡店喺附近。', 'The café is nearby.', 'gaa3 fe1 dim3 hai2 fu6 gan6.'),
('7bac4990-83cd-5d5a-a7b9-20993706544a', 4, '遠唔遠呀？', 'Is it far?', 'jyun5 m4 jyun5 aa3?'),
('7bac4990-83cd-5d5a-a7b9-20993706544a', 5, '多謝你幫手！', 'Thanks for your help!', 'do1 ze6 nei5 bong1 sau2!'),
('3d4108ec-b758-536c-ac51-8480408899ef', 1, 'Как прошел твой день в школе, Мин?', 'How was your day at school, Min?', 'Kak proshel tvoy den'' v shkole, Min?'),
('3d4108ec-b758-536c-ac51-8480408899ef', 2, 'Сегодня днём в автобусе было многолюдно?', 'Did the bus ride feel crowded this afternoon?', 'Segodnya dnom v avtobuse bylo mnogolyudno?'),
('3d4108ec-b758-536c-ac51-8480408899ef', 3, 'Покажи мне домашнее задание, чтобы мы могли спланировать перерывы.', 'Show me the homework so we can plan breaks.', 'Pokazhi mne domashneye zadaniye, chtoby my mogli splanirovat'' pereryvy.'),
('3d4108ec-b758-536c-ac51-8480408899ef', 4, 'Тщательно упакуйте свой арт-проект на завтра.', 'Pack your art project carefully for tomorrow.', 'Tshchatel''no upakuyte svoy art-proyekt na zavtra.'),
('0e3c1bf3-8153-5c4a-924f-1a6dbd1a691b', 1, '敏，你今日喺學校過得點呀?', 'How was your day at school, Min?', 'man5 nei5 gam1jat6 hai2 hok6haau6 gwo3 dak1 dim2 aa4'),
('0e3c1bf3-8153-5c4a-924f-1a6dbd1a691b', 2, '今日下午搭巴士覺得多人嗎？', 'Did the bus ride feel crowded this afternoon?', 'gam1jat6 haa6ng5 daap3 baa1si2 gok3dak1 do1 jan4 maa3'),
('0e3c1bf3-8153-5c4a-924f-1a6dbd1a691b', 3, '畀我睇下功課，咁我哋可以安排休息時間', 'Show me the homework so we can plan breaks.', 'bei3 ngo5 tai2haa5 gung1fo3 gam3 ngo5dei6 ho2ji5 on1paai4 jau1sik1si4gaan3'),
('0e3c1bf3-8153-5c4a-924f-1a6dbd1a691b', 4, '小心咁整理你嘅藝術項目帶返屋企明日用', 'Pack your art project carefully for tomorrow.', 'siu2sam1 gam3 zing2lei5 nei5 ge3 ngai6seot6 hong6muk6 daai3 faan1uk1kei2 ming4jat6 jung6'),
('5bd6a4bb-90e5-503c-878d-cbc55b582990', 1, 'Ка Минг, ты уже почти вернулся в кампус?', 'Ka Ming, are you almost back on campus?', 'Ka Ming, ty uzhe pochti vernulsya v kampus?'),
('5bd6a4bb-90e5-503c-878d-cbc55b582990', 2, 'Сначала возьмите из шкафчика учебник по естествознанию.', 'Grab the science textbook from your locker first.', 'Snachala voz''mite iz shkafchika uchebnik po yestestvoznaniyu.'),
('5bd6a4bb-90e5-503c-878d-cbc55b582990', 3, 'Поздний звонок прозвенит через пять минут, так что дышите и сосредоточьтесь.', 'The late bell rings in five minutes, so breathe and focus.', 'Pozdniy zvonok prozvenit cherez pyat'' minut, tak chto dyshite i sosredotoch''tes''.'),
('5bd6a4bb-90e5-503c-878d-cbc55b582990', 4, 'Просмотрите исторические заметки сегодня вечером, чтобы чувствовать себя готовыми.', 'Review the history notes tonight so you feel ready.', 'Prosmotrite istoricheskiye zametki segodnya vecherom, chtoby chuvstvovat'' sebya gotovymi.'),
('579c29c3-ea1a-5b14-acb6-330d568371ae', 1, '家明，你快返學校未？', 'Ka Ming, are you almost back on campus?', 'gaa1 ming4 nei5 faai3 faan1hok6 haau6 mei6'),
('579c29c3-ea1a-5b14-acb6-330d568371ae', 2, '首先喺你嘅儲物櫃攞科學課本', 'Grab the science textbook from your locker first.', 'sau2sin1 hai2 nei5 ge3 cyu5mat6gwai6 lo2 fo1hok6 fo3bun2'),
('579c29c3-ea1a-5b14-acb6-330d568371ae', 3, '喇叭聲五分鐘後響，深呼吸同專注', 'The late bell rings in five minutes, so breathe and focus.', 'laa3baa1 seng1 ng5 fan1zung1 hau6 hoeng2 sam1fu1kap1 tung4 zyun1zyu3'),
('579c29c3-ea1a-5b14-acb6-330d568371ae', 4, '今晚溫習歷史筆記，令你準備好。', 'Review the history notes tonight so you feel ready.', 'gam1maan1 wan1zaap6 lik6si2 bat1gei3 ling6 nei5 zeon2bei6 hou2'),
('b8eb5456-d7f8-54a0-81ac-207f81514fd1', 1, 'Линглинг, ночной ветерок снова пробрался в окно?', 'Lingling, did the night breeze sneak through the window again?', 'Lingling, nochnoy veterok snova probralsya v okno?'),
('b8eb5456-d7f8-54a0-81ac-207f81514fd1', 2, 'Я согрею для вас двоих термос с горячим чаем.', 'I will warm a thermos of hot tea for you two.', 'YA sogreyu dlya vas dvoikh termos s goryachim chayem.'),
('b8eb5456-d7f8-54a0-81ac-207f81514fd1', 3, 'Проверьте, действительно ли включился таймер обогревателя.', 'Check whether the space heater timer actually turned on.', 'Prover''te, deystvitel''no li vklyuchilsya taymer obogrevatelya.'),
('b8eb5456-d7f8-54a0-81ac-207f81514fd1', 4, 'Давайте завтра отследим качество сна и сравним записи.', 'Let us track sleep quality tomorrow and compare notes.', 'Davayte zavtra otsledim kachestvo sna i sravnim zapisi.'),
('f9027790-d7b5-5084-b078-9c696126ecb4', 1, '玲玲，夜風又偷偷從窗入嚟㗎？', 'Lingling, did the night breeze sneak through the window again?', 'ling4ling4 je6 fung1 jau6 tau1tau1 cung4 coeng1 jap6 lai4gaa3'),
('f9027790-d7b5-5084-b078-9c696126ecb4', 2, '我會為你哋兩個暖一個保溫壺嘅熱茶', 'I will warm a thermos of hot tea for you two.', 'ngo5 wui5 wai6 nei5dei6 loeng5 go3 nyun5 jat1go3 bou2wan1 wu4 ge3 jit6caa4'),
('f9027790-d7b5-5084-b078-9c696126ecb4', 3, '檢查空氣暖爐定時器是否真正啟動', 'Check whether the space heater timer actually turned on.', 'gim2caa4 hung1hei3 nyun5lou4 ding6si4 hei3 si6fau2 zan1zing3 kai2 dung6'),
('f9027790-d7b5-5084-b078-9c696126ecb4', 4, '我哋聽日追蹤訓眠質素同埋比較一下記錄', 'Let us track sleep quality tomorrow and compare notes.', 'ngo5dei6 ting1jat6 zeoi1zung1 fan3 min4 zat1sou3 tung4maai4 bei2gaau3 jat1haa5 gei3luk6'),
('685df1ce-cdca-5d68-a881-f35acff8746b', 1, 'Джеймс, как ты относишься к сегодняшней встрече с клиентом?', 'James, how are you feeling about the client meeting today?', 'Dzheyms, kak ty otnosish''sya k segodnyashney vstreche s kliyentom?'),
('685df1ce-cdca-5d68-a881-f35acff8746b', 2, 'Давайте обменяемся комментариями перед еженедельным звонком.', 'Let us swap feedback notes before the weekly call.', 'Davayte obmenyayemsya kommentariyami pered yezhenedel''nym zvonkom.'),
('685df1ce-cdca-5d68-a881-f35acff8746b', 3, 'Можете ли вы обновить краткое описание проекта, пока я отправляю электронное письмо менеджеру?', 'Can you update the project brief while I email the manager?', 'Mozhete li vy obnovit'' kratkoye opisaniye proyekta, poka ya otpravlyayu elektronnoye pis''mo menedzheru?'),
('685df1ce-cdca-5d68-a881-f35acff8746b', 4, 'Нам следует выделить время для перерывов, чтобы сократить сроки.', 'We should block time for breaks so the deadlines feel lighter.', 'Nam sleduyet vydelit'' vremya dlya pereryvov, chtoby sokratit'' sroki.'),
('1bf4c8dd-2ad0-5ba1-847b-048797491992', 1, 'James，你今日對客戶會議有咩感覺？', 'James, how are you feeling about the client meeting today?', 'nei5 gam1jat6 deoi3 haak3wu6 wui6ji5 jau5me1 gam2gok3'),
('1bf4c8dd-2ad0-5ba1-847b-048797491992', 2, '我哋喺每週電話會議前互換意見筆記', 'Let us swap feedback notes before the weekly call.', 'ngo5dei6 hai2 mui5zau1 din6waa2wui6ji5 cin4 wu6wun6 ji3gin3 bat1gei3'),
('1bf4c8dd-2ad0-5ba1-847b-048797491992', 3, '你可以更新項目簡報，我去發電郵俾經理？', 'Can you update the project brief while I email the manager?', 'nei5 ho2ji5 gang1san1 hong6muk6 gaan2bou3 ngo5 heoi3 faat3din6 jau4 bei2 ging1lei5'),
('1bf4c8dd-2ad0-5ba1-847b-048797491992', 4, '我哋應該安排時間休息，令截止日期感覺冇咁迫。', 'We should block time for breaks so the deadlines feel lighter.', 'ngo5dei6 jing1goi1 on1paai4 si4gaan1 jau1sik1 ling6 zit6zi2 jat6kei4 gam2gok3 mou5 gam3 bik1'),
('3d2264d6-b6f3-53ea-aa93-12e89e4ef978', 1, 'Лиза, эти кроссовки на ощупь лучше, чем предыдущая пара?', 'Lisa, do these sneakers feel better than the last pair?', 'Liza, eti krossovki na oshchup'' luchshe, chem predydushchaya para?'),
('3d2264d6-b6f3-53ea-aa93-12e89e4ef978', 2, 'Давайте дважды проверим таблицу размеров, прежде чем платить.', 'Let us double check the size chart before we pay.', 'Davayte dvazhdy proverim tablitsu razmerov, prezhde chem platit''.'),
('3d2264d6-b6f3-53ea-aa93-12e89e4ef978', 3, 'На всякий случай спрошу о правилах возврата.', 'I will ask about the return policy just in case.', 'Na vsyakiy sluchay sproshu o pravilakh vozvrata.'),
('3d2264d6-b6f3-53ea-aa93-12e89e4ef978', 4, 'Пройдите полный круг, чтобы проверить комфорт и равновесие.', 'Walk a full lap to test the comfort and balance.', 'Proydite polnyy krug, chtoby proverit'' komfort i ravnovesiye.'),
('c6c533eb-a43a-5210-bace-d102b88b974c', 1, 'Lisa，呢對運動鞋比上一對舒服啲嗎？', 'Lisa, do these sneakers feel better than the last pair?', 'ne1 deoi3 wan6dung6haai4 bei2 soeng5 jat1deoi3 syu1fuk6 di1 maa3'),
('c6c533eb-a43a-5210-bace-d102b88b974c', 2, '喺我哋付款之前，唔該我哋再仔細核對一次尺碼表', 'Let us double check the size chart before we pay.', 'hai2 ngo5dei6 fu6fun2 zi1cin4 m4goi1 ngo5dei6 zoi3 zi2sai3 hat6deoi3 jat1ci3 cek3maa5 biu2'),
('c6c533eb-a43a-5210-bace-d102b88b974c', 3, '我會問返貨政策以防萬一', 'I will ask about the return policy just in case.', 'ngo5 wui5 man6faan1 fo3 zing3caak3 ji5fong4maan6jat1'),
('c6c533eb-a43a-5210-bace-d102b88b974c', 4, '行完整一圈以測試舒適度同平衡', 'Walk a full lap to test the comfort and balance.', 'haang4 jyun4zing2 jat1 gyun6 ji5 caak1si3 syu1sik1 dou6 tung4 ping4hang4'),
('8f33449c-784a-5533-b35c-d6334be524be', 1, 'Энди, что тебе в ней больше всего нравится?', 'Andy, what do you like most about her so far?', 'Endi, chto tebe v ney bol''she vsego nravitsya?'),
('8f33449c-784a-5533-b35c-d6334be524be', 2, 'Должны ли мы запланировать двойное свидание за кофе на следующей неделе?', 'Should we plan a double coffee date next week?', 'Dolzhny li my zaplanirovat'' dvoynoye svidaniye za kofe na sleduyushchey nedele?'),
('8f33449c-784a-5533-b35c-d6334be524be', 3, 'Расскажи мне самую смешную переписку, которой вы переписывались.', 'Tell me the funniest text thread you two shared.', 'Rasskazhi mne samuyu smeshnuyu perepisku, kotoroy vy perepisyvalis''.'),
('8f33449c-784a-5533-b35c-d6334be524be', 4, 'Не забывайте праздновать медленно и наслаждаться новым темпом.', 'Remember to celebrate slowly and enjoy the new pace.', 'Ne zabyvayte prazdnovat'' medlenno i naslazhdat''sya novym tempom.'),
('3c749e84-a296-5260-8825-5e5a75492e8d', 1, 'Andy，到而家你最鍾意佢啲乜嘢？', 'Andy, what do you like most about her so far?', 'dou2 ji4gaa1 nei5 zeoi3zung1ji3 keoi5 di1 mat1je5'),
('3c749e84-a296-5260-8825-5e5a75492e8d', 2, '我哋下星期應唔應該安排一次雙人咖啡約會?', 'Should we plan a double coffee date next week?', 'ngo5dei6 haa6sing1kei4 jing1 m4 jing1goi1 on1paai4 jat1ci3 soeng1jan4 gaa3fe1 joek3wui2'),
('3c749e84-a296-5260-8825-5e5a75492e8d', 3, '講畀我聽你哋兩個分享過最搞笑嘅訊息對話。', 'Tell me the funniest text thread you two shared.', 'gong2 bei3 ngo5 teng1 nei5dei6 loeng5 go3 fan1hoeng2 gwo3 zeoi3 gaau2siu3 ge3 seon3sik1 deoi3waa2'),
('3c749e84-a296-5260-8825-5e5a75492e8d', 4, '記住慢慢慶祝，享受新的節奏', 'Remember to celebrate slowly and enjoy the new pace.', 'gei3zyu6 maan6maan2 hing3zuk1 hoeng2sau6 san1 dik1 zit3zau3'),
('03d64d4e-7b70-527b-9db7-1d816c1fd60d', 1, 'Джек, ты уже подписал поздравительную открытку?', 'Jack, did you sign the birthday card yet?', 'Dzhek, ty uzhe podpisal pozdravitel''nuyu otkrytku?'),
('03d64d4e-7b70-527b-9db7-1d816c1fd60d', 2, 'Я могу упаковать подарок, пока ты гладишь рубашку.', 'I can wrap the gift while you iron the shirt.', 'YA mogu upakovat'' podarok, poka ty gladish'' rubashku.'),
('03d64d4e-7b70-527b-9db7-1d816c1fd60d', 3, 'Стоит ли нам вызвать каршеринг или сесть на автобус для вечеринок?', 'Should we call a ride share or catch the party bus?', 'Stoit li nam vyzvat'' karshering ili sest'' na avtobus dlya vecherinok?'),
('03d64d4e-7b70-527b-9db7-1d816c1fd60d', 4, 'Оставьте место для торта, потому что хозяин заказал дополнительно.', 'Save room for cake because the host ordered extra.', 'Ostav''te mesto dlya torta, potomu chto khozyain zakazal dopolnitel''no.'),
('0029b7d6-e6cd-58c6-90fa-db3b391089aa', 1, 'Jack, 你簽咗生日卡未？', 'Jack, did you sign the birthday card yet?', 'nei5 cim1 zo2 saang1jat6kaat1 mei6'),
('0029b7d6-e6cd-58c6-90fa-db3b391089aa', 2, '我可以包禮物，你去熨衫。', 'I can wrap the gift while you iron the shirt.', 'ngo5 ho2ji5 baau1 lai5mat6 nei5 heoi3 tong3saam1'),
('0029b7d6-e6cd-58c6-90fa-db3b391089aa', 3, '我哋應該叫共乘車定搭派對巴士？', 'Should we call a ride share or catch the party bus?', 'ngo5dei6 jing1goi1 giu3 gung6sing4 ce1 ding6 daap3 paai3deoi3 baa1si2'),
('0029b7d6-e6cd-58c6-90fa-db3b391089aa', 4, '留位食蛋糕，因為主人叫咗多啲。', 'Save room for cake because the host ordered extra.', 'lau4 wai2 sik6 daan6gou1 jan1wai6 zyu2jan2 giu3 zo2 do1 di1'),
('94cd4e11-e8e8-51ff-919a-cd23b68211cb', 1, 'Эта крошечная квартирка кажется переполненной, поэтому давайте перерисуем план этажа.', 'This tiny apartment feels packed, so let us redraw the floor plan.', 'Eta kroshechnaya kvartirka kazhetsya perepolnennoy, poetomu davayte pererisuyem plan etazha.'),
('94cd4e11-e8e8-51ff-919a-cd23b68211cb', 2, 'Можем ли мы построить больше ящиков для хранения вещей в коридоре?', 'Can we build more storage boxes for the hallway?', 'Mozhem li my postroit'' bol''she yashchikov dlya khraneniya veshchey v koridore?'),
('94cd4e11-e8e8-51ff-919a-cd23b68211cb', 3, 'Я спрошу хозяина о складном столике или полке.', 'I will ask the landlord about a folding table or shelf.', 'YA sproshu khozyaina o skladnom stolike ili polke.'),
